import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, Link, useLocation, Navigate } from 'react-router-dom';
import './App.css';

// --- КОМПОНЕНТЫ: ЛОГИН, МЕНЮ, ПРОФИЛЬ ---
const AuthScreen = ({ onLogin, onRegister }) => {
  const [isLogin, setIsLogin] = useState(true);
  const [email, setEmail] = useState('');
  const [pass, setPass] = useState('');
  const [name, setName] = useState('');
  return (
    <div className="login-page">
      <div className="login-card fade-in">
        <div className="logo-icon">☕</div>
        <h2 className="login-title">Etika Paradise</h2>
        <div className="auth-form">
          {!isLogin && <input type="text" placeholder="Имя" className="auth-input" onChange={e => setName(e.target.value)} />}
          <input type="email" placeholder="Email" className="auth-input" onChange={e => setEmail(e.target.value)} />
          <input type="password" placeholder="Пароль" className="auth-input" onChange={e => setPass(e.target.value)} />
          <button className="btn-auth-submit" onClick={() => isLogin ? onLogin(email, pass) : onRegister(name, email, pass)}>
            {isLogin ? 'Войти' : 'Создать'}
          </button>
        </div>
        <p className="toggle-auth" onClick={() => setIsLogin(!isLogin)}>{isLogin ? 'Регистрация' : 'Вход'}</p>
      </div>
    </div>
  );
};

const Menu = ({ cart, onAddToCart, onOrder }) => {
  const items = [
    { id: 1, name: 'Капучино', price: 250, img: '☕', desc: 'Классический баланс' },
    { id: 3, name: 'Круассан', price: 210, img: '🥐', desc: 'Сливочный и хрустящий' }
  ];
  const total = cart.reduce((sum, i) => sum + i.price, 0);
  return (
    <div className="page fade-in">
      <h2>Paradise Menu</h2>
      {items.map(i => (
        <div key={i.id} className="product-card">
          <div className="product-emoji">{i.img}</div>
          <div className="product-info">
            <div className="name-price"><h4>{i.name}</h4><span className="price-tag">{i.price} ₽</span></div>
            <p className="product-desc">{i.desc}</p>
          </div>
          <button className="btn-add-minimal" onClick={() => onAddToCart(i)}>+</button>
        </div>
      ))}
      {cart.length > 0 && (
        <div className="cart-floating fade-in">
          <div className="cart-content">
            <div className="cart-text"><span>{cart.length} шт.</span><strong>{total} ₽</strong></div>
            <button className="btn-order-now" onClick={onOrder}>Оформить</button>
          </div>
        </div>
      )}
    </div>
  );
};

