// --- АДМИН-ПАНЕЛЬ (Новое) ---
const AdminPanel = () => {
  const [allOrders, setAllOrders] = useState([]);

  const fetchAll = () => fetch('http://localhost:8000/index.php').then(res => res.json()).then(setAllOrders);

  useEffect(() => {
    fetchAll();
    const int = setInterval(fetchAll, 3000);
    return () => clearInterval(int);
  }, []);

  const updateStatus = async (id, status) => {
    await fetch('http://localhost:8000/index.php', {
      method: 'PATCH',
      body: JSON.stringify({ id, status })
    });
    fetchAll();
  };

  return (
    <div className="page fade-in">
      <h2>Панель управления</h2>
      <div className="order-list">
        {allOrders.map(o => (
          <div key={o.id} className="order-card-compact">
            <div className="order-top">
              <span><strong>{o.user_name || 'Гость'}</strong></span>
              <span>{o.total_amount} ₽</span>
            </div>
            <p className="o-desc">#{o.id}: {o.description}</p>
            <div className="admin-actions">
              <button onClick={() => updateStatus(o.id, 'Готов')} className="btn-status green">Готов</button>
              <button onClick={() => updateStatus(o.id, 'Выдан')} className="btn-status blue">Выдан</button>
              <span className="status-label">{o.status}</span>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

const BottomNav = () => {
  const loc = useLocation();
  return (
    <nav className="bottom-bar">
      <Link to="/" className={`nav-link ${loc.pathname === '/' ? 'active' : ''}`}><span>🍴</span> Меню</Link>
      <Link to="/profile" className={`nav-link ${loc.pathname === '/profile' ? 'active' : ''}`}><span>👤</span> Профиль</Link>
      <Link to="/admin" className={`nav-link ${loc.pathname === '/admin' ? 'active' : ''}`}><span>⚙️</span> Админ</Link>
    </nav>
  );
};

export default function App() {
  const [user, setUser] = useState(JSON.parse(localStorage.getItem('user')));
  const [orders, setOrders] = useState([]);
  const [cart, setCart] = useState([]);

  useEffect(() => {
    if (!user) return;
    const fetchMy = () => fetch(`http://localhost:8000/index.php?user_id=${user.id}`).then(res => res.json()).then(data => setOrders(Array.isArray(data) ? data : []));
    fetchMy();
    const int = setInterval(fetchMy, 5000);
    return () => clearInterval(int);
  }, [user]);

  const auth = async (action, body) => {
    const res = await fetch('http://localhost:8000/index.php', { method: 'POST', body: JSON.stringify({ action, ...body })});
    const data = await res.json();
    if (data.id) { setUser(data); localStorage.setItem('user', JSON.stringify(data)); } else alert(data.error);
  };

  if (!user) return <AuthScreen onLogin={(email, password) => auth('login', { email, password })} onRegister={(name, email, password) => auth('register', { name, email, password })} />;

  return (
    <Router>
      <div className="paradise-app">
        <Routes>
          <Route path="/" element={<Menu cart={cart} onAddToCart={i => setCart([...cart, i])} onOrder={async () => {
            await fetch('http://localhost:8000/index.php', { method: 'POST', body: JSON.stringify({ user_id: user.id, description: cart.map(i => i.name).join(', '), total_amount: cart.reduce((s, i) => s + i.price, 0) })});
            setCart([]); alert('Заказ принят!');
          }} />} />
          <Route path="/profile" element={<Profile user={user} orders={orders} onLogout={() => {setUser(null); localStorage.removeItem('user');}} />} />
          <Route path="/admin" element={<AdminPanel />} />
        </Routes>
        <BottomNav />
      </div>
    </Router>
  );
}
